        exchangeStructure: P21Decode.ExchangeStructure
      ) {
        let numParams = 2
        guard parameters.count == numParams
        else { exchangeStructure.error = "number of p21 parameters(\(parameters.count)) are different from expected(\(numParams)) for partial entity(\(Self.entityName)) constructor"; return nil }

        guard case .success(let p0) = exchangeStructure.recoverRequiredParameter(as: sDATUM_OR_COMMON_DATUM.self, from: parameters[0])
        else { exchangeStructure.add(errorContext: "while recovering parameter [0]BASE for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p1) = exchangeStructure.recoverOptionalParameter(as: SDAI.SET<
          sDATUM_REFERENCE_MODIFIER>.self, from: parameters[1])
        else { exchangeStructure.add(errorContext: "while recovering parameter [1]MODIFIERS for partial entity(\(Self.entityName)) constructor"); return nil }

        self.init( BASE: p0, MODIFIERS: p1 )
      }
    }
  }
}
